mapper.select:
select id, title, cover_url, location, signup_limit, current_signup_count, wait_limit, status, audit_status, signup_start_time, signup_end_time, activity_start_time, activity_end_time from activity where is_deleted = 0
and ( title like concat('%', #{keyword}, '%') or location like concat('%', #{keyword}, '%') )
and status = #{status}
and audit_status = #{auditStatus}
order by id desc

select s.id, s.activity_id, a.title as activity_title, a.location as activity_location, s.signup_time, s.signup_status, s.sign_status, s.sign_time, s.cancel_time, s.wait_order from activity_signup s left join activity a on s.activity_id = a.id where s.user_id = #{userId}
and s.signup_status = #{signupStatus}
order by s.id desc
